// Match Invoice with Purchase Order
const invoiceData = JSON.parse($input.first().json.message.content);
const purchaseOrders = $('Fetch Purchase Orders').all().map(item => item.json);

// Find matching PO
let matchedPO = null;
let matchScore = 0;

if (invoiceData.purchase_order_number) {
  matchedPO = purchaseOrders.find(po => 
    po.po_number === invoiceData.purchase_order_number
  );
}

// Calculate match score
if (matchedPO) {
  const amountMatch = Math.abs(matchedPO.total_amount - invoiceData.total_amount) < 1;
  const vendorMatch = matchedPO.vendor_name.toLowerCase() === invoiceData.vendor_name.toLowerCase();

  if (amountMatch && vendorMatch) {
    matchScore = 100;
  } else if (amountMatch || vendorMatch) {
    matchScore = 70;
  } else {
    matchScore = 50;
  }
}

// Determine status
let status = 'pending_review';
let requires_approval = true;

if (matchScore === 100 && invoiceData.confidence_score >= 90) {
  status = 'auto_approved';
  requires_approval = false;
} else if (matchScore >= 70) {
  status = 'pending_manual_review';
} else {
  status = 'pending_review';
}

// Prepare invoice record
const invoiceRecord = {
  invoice_id: 'INV-' + Date.now(),
  invoice_number: invoiceData.invoice_number,
  invoice_date: invoiceData.invoice_date,
  due_date: invoiceData.due_date,
  vendor_name: invoiceData.vendor_name,
  vendor_address: invoiceData.vendor_address,
  vendor_tax_id: invoiceData.vendor_tax_id,
  subtotal: invoiceData.subtotal,
  tax_amount: invoiceData.tax_amount,
  tax_percentage: invoiceData.tax_percentage,
  total_amount: invoiceData.total_amount,
  currency: invoiceData.currency,
  line_items: JSON.stringify(invoiceData.line_items),
  payment_terms: invoiceData.payment_terms,
  purchase_order_number: invoiceData.purchase_order_number,
  matched_po: matchedPO ? matchedPO.po_number : null,
  match_score: matchScore,
  confidence_score: invoiceData.confidence_score,
  status: status,
  requires_approval: requires_approval,
  drive_url: $('Save to Google Drive').item.json.webViewLink,
  received_at: $now.toISO(),
  processed_at: $now.toISO()
};

return [{ json: invoiceRecord }];

