// Check for upcoming and overdue payments
const invoices = $input.all().map(item => item.json);
const today = new Date();
const in3Days = new Date(today.getTime() + 3 * 24 * 60 * 60 * 1000);

const upcomingPayments = [];
const overduePayments = [];

invoices.forEach(invoice => {
  if (invoice.status === 'approved' || invoice.status === 'auto_approved') {
    const dueDate = new Date(invoice.due_date);

    if (dueDate < today) {
      overduePayments.push(invoice);
    } else if (dueDate <= in3Days) {
      upcomingPayments.push(invoice);
    }
  }
});

return [{
  json: {
    upcoming_payments: upcomingPayments,
    overdue_payments: overduePayments,
    check_date: today.toISOString()
  }
}];
